from reporting.templates import CSS
from reporting.report_sections import disclaimer
def build(report):
 rows=''.join(f"<tr><td>{x['ticker']}</td><td>{x['action']}</td><td>{x['score']:.3f}</td><td>{x['prediction']['probability']:.1%}</td><td>{x['mc']['expected_return']:.2%}</td><td>{x['mc']['var_95']:.2%}</td><td>{x['weight']:.1%}</td></tr>" for x in report.get('picks',[])) or '<tr><td colspan="7">CASH MODE / no allocations</td></tr>'
 forecast=report.get('regime_forecast',{});health=report.get('universe_health',{});analytics=report.get('analytics',{});paper=analytics.get('paper',{});debate=report.get('debate',{})
 narrative=report.get('narrative',{}).get('text','No narrative available.')
 return f'''<html><head><style>{CSS}</style></head><body><h1>Systematic Swing Research Briefing</h1><div class="tile">As-of: {report['date']} | Decision: <b>{report['decision']}</b> | Regime: {report['regime']}</div><h2>Market & Regime Dashboard</h2><table><tr><th>Regime</th><th>P(bear flip, 5d)</th><th>P(vol spike, 5d)</th><th>Universe loaded</th><th>Deep analysis</th></tr><tr><td>{report['regime']}</td><td>{forecast.get('flip_bearish_5d',0):.1%}</td><td>{forecast.get('vol_spike_5d',0):.1%}</td><td>{health.get('loaded',0)}/{health.get('requested',0)}</td><td>{health.get('deep_analyzed',0)}</td></tr></table><h2>Ranked Research Watchlist</h2><table><tr><th>Ticker</th><th>Action</th><th>Score</th><th>ML P(positive)</th><th>MC EV</th><th>MC VaR 95</th><th>Allocation</th></tr>{rows}</table><h2>Risk, Calibration & Paper Trading</h2><p>Kill switch: {report['kill_switch']['reason']} | Paper closed trades: {paper.get('closed_trades',0)} | Win rate: {paper.get('win_rate',0):.1%} | Risk of ruin proxy: {analytics.get('risk_of_ruin',0):.1%}</p><p>Stress scenarios and model calibration/drift records are persisted in the accompanying SQLite artifact and dashboard.</p><h2>Agent Debate & Attribution</h2><p>Bull score: {debate.get('bull_score',0):.2f}; Bear score: {debate.get('bear_score',0):.2f}; Committee verdict: {debate.get('action','CASH')}</p><p>{narrative}</p><p>Equity curve chart: <code>equity_curve_chart.html</code> in the research artifact pack.</p>{disclaimer()}</body></html>'''
